import{_ as e,o as l,c as d,a2 as r}from"./chunks/framework.Crpw6aS5.js";const x=JSON.parse('{"title":"董事长信 - 1990","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1990年/翻译.md","filePath":"01_letters/1990年/翻译.md"}'),n={name:"01_letters/1990年/翻译.md"};function a(i,t,s,p,o,c){return l(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="董事长信-1990" tabindex="-1">董事长信 - 1990 <a class="header-anchor" href="#董事长信-1990" aria-label="Permalink to &quot;董事长信 - 1990&quot;">​</a></h1><p>1991年3月1日</p><p>致伯克希尔·哈撒韦公司全体股东：</p><p>去年我们预测，&quot;未来三年至少有一年伯克希尔净值缩水&quot;，1990年下半年我们一路走，很快就证明这个预测对，但是年底股价反弹，年底净值涨了三亿六千二百万，增长7.3%，过去二十六年（现任管理层接手以来），每股账面价值从19.46涨到4612.06美元，年复利23.2%。</p><p>1990年增长率不好，因为我们四大重仓股市值整体变化不大，去年我告诉你，这四家公司——首都城市/ABC、可口可乐、GEICO、华盛顿邮报——生意好管理好，但是市场已经给了很高估值，年末价格比去年更吸引人一点，两家媒体公司跌了不少，行业变化是对的，可口可乐涨了不少，也是对的，所以年底我们&quot;永久四个&quot;价格，虽然不吸引人，比去年好一点。</p><p>伯克希尔二十六年记录预测未来没用，一年记录更没用，我们继续目标就是平均每年内在价值增长15%，我们也一直告诉你，基数越大越难做到，现在五十三亿净资产基数，越来越难，如果我们做到平均15%，股东肯定不错，前提就是，你买的时候溢价，卖的时候还是溢价，你的回报就和公司一样，如果你买的时候溢价很大，卖的时候溢价变小了，你的回报就不如公司。</p><p>理想情况，伯克希尔股价一直围绕内在价值，我们希望股价就在内在价值附近波动，我们不喜欢股价波动太大，1989年内在价值涨得比账面价值少，账面价值涨了44%，市场价涨了85%；1990年账面价值内在价值小幅涨，市场价跌了23%，我们也习惯了。</p><p>伯克希尔内在价值一直大幅超过账面价值，我们说不准精确数，查理和我估计差个10%很正常，内在价值本来就是估计数，我们两个人估计差一点很正常，但我们知道，我们持有这些 exceptional 生意，价值肯定比账面高很多，这些超额价值大部分都是我们现在经理人创造的，查理和我什么都没做，我们就是找到这些天才经理人，我们给他们环境，让他们干活，他们就创造价值，我们就分钱。</p><h2 id="透视盈利" tabindex="-1">透视盈利 <a class="header-anchor" href="#透视盈利" aria-label="Permalink to &quot;透视盈利&quot;">​</a></h2><p>盈利这个词，听起来精确，碰到骗子，盈利就像橡皮泥，很多美国大公司财富就是会计海市蜃楼创造出来，这种造假现在一直有，很多重要财富就是这么来的。</p><p>伯克希尔情况不一样，我们很多大投资，公司赚了很多，我们只算拿到的股息，留存的不算，GAAP就是这么要求的，比如，我们持有首都城市ABC 17%，去年我们占这家公司盈利八千三百万，GAAP只算五十三万股息，剩下八千二百万留在首都城市，帮我们赚钱，不算我们盈利，我们觉得这个不对，我们&quot;透视盈利&quot;就是：我们投资公司留存盈利，我们占有的部分，加上我们自己报告盈利，这样才对。</p><p>我们理念就是，我们不在乎盈利记不记在我们账上，我们在乎这些盈利能不能帮我们增值，可口可乐用留存收益回购股票，我们持股比例就越来越高，我们持股内在价值就越来越高，本来可口可乐把钱分给我们，我们拿到还要交税，再买股票，肯定不如公司自己留着帮我们买，所以透视盈利才是真盈利。</p><p>我们估计，1990年我们透视盈利大约五亿九千万，过去我们希望透视盈利每年增长15%，去年超过一点，明年肯定不到，吉雷特可转债转成普通股，每年会减少我们透视盈利大概三千五百万，媒体盈利我们直接间接肯定也会降，不管结果怎么样，我们每年都会给你报告透视盈利。</p><h2 id="非保险运营" tabindex="-1">非保险运营 <a class="header-anchor" href="#非保险运营" aria-label="Permalink to &quot;非保险运营&quot;">​</a></h2><p>你看第51页加总我们非保险业务，1990年税后平均股权回报率51%，放到财富五百强，这个回报率能排前二十，我们没杠杆，几乎所有主要设施都是自己所有，欠的债很少，现金差不多等于负债，所以这个回报率真的很了不起，不是杠杆带来的，也不是行业顺风，就是经理人厉害，这些生意就是家具零售、糖果、吸尘器，都非常普通，就是管理出色。</p><p>一个个看：</p><ul><li><p><strong>Borsheim&#39;s</strong>，加入伯克希尔第一年，销售涨了18%，我们相信它现在就是美国单店珠宝店销量最大，Ike Friedman家族真厉害，奥马哈才六十万人，一年卖一亿多珠宝，就是低价大库存，低成本，低价格，带来大流量，越来越多全国客户邮购，口碑传出去，客户越来越多， honor system 退货，从来没损失过，所以Borsheim就是诚信创造奇迹，不信你自己去看看。</p></li><li><p><strong>内布拉斯加家具城</strong>，1990年销售一亿五千九百万，涨了4%，NFM现在肯定是美国最大单店家居店，我们公式和Borsheim一模一样，低成本低价格，大库存大流量，现在奥马哈之外，开车一百三十英里都来买，所以就是我们赢了，去年NFM卖喜诗糖果，居然卖得比加州喜诗店还多，这就是协同效应，我们都没想到。</p></li><li><p><strong>喜诗糖果</strong>，1990年销量创纪录，圣诞节前西部商场人流量降了，圣诞节销量略降一点，价格涨了5%，利润率还提高了，环境不好零售，查克·哈金斯做得非常出色，阿尔伯克基一个店房东不租了，要我们搬差地方，顾客集体抗议，最后房东让步，顾客帮我们赢了，这就是顾客喜欢喜诗，真的少见。</p></li><li><p><strong>水牛城新闻</strong>，媒体行业现在比几年前脆弱，因为广告越来越分散，定价权下降，巴菲特承认，之前没预测到，现在看来，媒体价值比几年前大家想的要低，但是斯坦·利普西管理真出色，1990年收入只降了5%，大多数大报降得比这个多多，四季度下降更快，明年新闻纸涨价，人工也涨，所以明年利润肯定降，我们还是保持50%以上新闻版面，不会砍新闻，降低质量就是不对，逆境才要坚持。</p></li><li><p><strong>Fechheimer</strong>，制服业务，乔治·赫尔德曼69岁退休了，我们劝不动，现在赫尔德曼家族四个后代接着干，整合问题都差不多解决了，未来前景很好。</p></li><li><p><strong>Scott Fetzer</strong>，拉尔夫·谢伊管十九个 business，依然出色，Kirby三代吸尘器大卖，出口过去两年翻一番，过去四年翻五倍，1990年销量还涨20%，新产品推出也很成功，世界图书百科全书持续海外增长，我们买的时候拉尔夫就在这，现在还是一样出色，他管资本配置也特别好，帮我们产生很多自由现金流，所以我们买Scott Fetzer，买到拉尔夫真的和买到这些 business 一样值钱。</p></li></ul><h2 id="保险运营" tabindex="-1">保险运营 <a class="header-anchor" href="#保险运营" aria-label="Permalink to &quot;保险运营&quot;">​</a></h2><p>更新行业表格：</p><table tabindex="0"><thead><tr><th style="text-align:center;">年份</th><th style="text-align:center;">保费写出增长率</th><th style="text-align:center;">法定综合成本率</th><th style="text-align:center;">已发生损失增长率</th><th style="text-align:center;">GNP平减通胀率</th></tr></thead><tbody><tr><td style="text-align:center;">1981</td><td style="text-align:center;">3.8%</td><td style="text-align:center;">106.0</td><td style="text-align:center;">6.5%</td><td style="text-align:center;">9.6%</td></tr><tr><td style="text-align:center;">1982</td><td style="text-align:center;">3.7%</td><td style="text-align:center;">109.6</td><td style="text-align:center;">8.4%</td><td style="text-align:center;">6.5%</td></tr><tr><td style="text-align:center;">1983</td><td style="text-align:center;">5.0%</td><td style="text-align:center;">112.0</td><td style="text-align:center;">6.8%</td><td style="text-align:center;">3.8%</td></tr><tr><td style="text-align:center;">1984</td><td style="text-align:center;">8.5%</td><td style="text-align:center;">118.0</td><td style="text-align:center;">16.9%</td><td style="text-align:center;">3.8%</td></tr><tr><td style="text-align:center;">1985</td><td style="text-align:center;">22.1%</td><td style="text-align:center;">116.3</td><td style="text-align:center;">16.1%</td><td style="text-align:center;">3.0%</td></tr><tr><td style="text-align:center;">1986</td><td style="text-align:center;">22.2%</td><td style="text-align:center;">108.0</td><td style="text-align:center;">13.5%</td><td style="text-align:center;">2.6%</td></tr><tr><td style="text-align:center;">1987</td><td style="text-align:center;">9.4%</td><td style="text-align:center;">104.6</td><td style="text-align:center;">7.8%</td><td style="text-align:center;">3.1%</td></tr><tr><td style="text-align:center;">1988</td><td style="text-align:center;">4.4%</td><td style="text-align:center;">105.4</td><td style="text-align:center;">5.5%</td><td style="text-align:center;">3.2%</td></tr><tr><td style="text-align:center;">1989 (修正)</td><td style="text-align:center;">3.2%</td><td style="text-align:center;">109.2</td><td style="text-align:center;">7.7%</td><td style="text-align:center;">4.1%</td></tr><tr><td style="text-align:center;">1990 (估计)</td><td style="text-align:center;">4.5%</td><td style="text-align:center;">109.8</td><td style="text-align:center;">5.0%</td><td style="text-align:center;">4.1%</td></tr></tbody></table><p>来源：A.M. Best Co.</p><p>综合成本率低于100承保盈利，高于就是承保亏损，加上浮存金投资收益，通常107-111之间整体盈亏平衡，不包含股东资金赚的钱。</p><p>我们过去一直说，行业每年损失增长大约10%，哪怕整体通胀不高，过去二十五年平均每年涨11%，所以保费增长跟不上10%，承保亏损一定会越来越大，只是行业不景气的时候大家倾向低估，一时半会儿看不出来。</p><p>去年保费增长还是不到10%，所以承保结果继续恶化，今年估计再涨两个点，什么时候能变好呢？大多数保险公司经理都吓坏了，不敢写业务，价格涨够了，结果就变好，现在这个点还远，我们准备好了，价格对我们就写大业务，价格不对我们就停，现在保费规模不大，但很满意。</p><p>我们现在做大额巨灾再保险，就是原保险公司怕一次大灾难亏太多，买再保险，我们接，所以伯克希尔现在是美国最大巨灾再保 writer，我们愿意承担大风险，一次巨灾亏两亿五我们也认，所以每年要么赚接近一亿，要么亏超过两亿，大多数保险公司受不了这种波动，我们没关系，我们股东也能接受，我们就喜欢这样，我们宁愿要波动的15%，不要平稳的12%。</p><p>我们要强调三个点：</p><ol><li>我们预期这种业务，十年里大部分年盈利，偶尔一年巨亏，所以综合比例，不会一直在行业区间，要么很低要么很高。</li><li>这个业务历史数据没用，未来损失很难估计，价格对我们才接，价格不对我们不接，价格现在大部分巨灾再保价格还是不对。</li><li>我们做这个业务，就是资本够强，别人不敢接，我们敢接，所以这就是我们竞争优势。</li></ol><h2 id="怎么衡量保险公司盈利能力" tabindex="-1">怎么衡量保险公司盈利能力？ <a class="header-anchor" href="#怎么衡量保险公司盈利能力" aria-label="Permalink to &quot;怎么衡量保险公司盈利能力？&quot;">​</a></h2><p>大家一般看综合成本率，我们觉得不对，更好的衡量就是，<strong>承保亏了多少，对比你拿到多少浮存金</strong>，就是你收了保费，赔完了剩下钱你拿去投资，这个loss/float 比例才是衡量，低就是好，高就是不好。</p><p>浮存金就是，保险公司收了保费，未来要赔，所以你拿着别人钱投资，长期来看，只要承保不赚太狠，拿到浮存金就是好事，因为你拿这个钱能投资，只要投资收益好，就是好事。</p><p>我们伯克希尔从1967年进入保险，每年我们承保亏多少，平均浮存金多少，算一下资金成本，下表就是：</p><p>| 年份 | 承保亏损 | 平均浮存金 | 近似资金成本 | 长期国债收益率年底 | |:----😐:----------😐:------------😐:---------------😐 | 1967 | 盈利 | 0.37 | &lt;0 | 5.50% | | 1968 | 盈利 | 19.9 | &lt;0 | 5.90% | | 1969 | 盈利 | 23.4 | &lt;0 | 6.79% | | 1970 | 盈利 | 32.4 | &lt;0 | 6.25% | | 1971 | 盈利 | 52.5 | &lt;0 | 5.81% | | 1972 | 盈利 | 69.5 | &lt;0 | 5.82% | | 1973 | 盈利 | 73.3 | &lt;0 | 7.27% | | 1974 | 盈利 | 79.1 | &lt;0 | 8.13% | | 1975 | 盈利 | 102.6 | &lt;0 | 8.03% | | 1976 | 盈利 | 139.0 | &lt;0 | 7.97% | | 1977 | 盈利 | 190.4 | &lt;0 | 7.60% | | 1978 | 盈利 | 227.3 | &lt;0 | 10.08% | | 1979 | 盈利 | 237.0 | &lt;0 | 10.61% | | 1980 | 盈利 | 228.4 | &lt;0 | 11.94% | | 1981 | 11.08 | 253.2 | 4.38% | 13.61% | | 1982 | 24.40 | 390.2 | 6.25% | 10.64% | | 1983 | 26.65 | 442.0 | 6.03% | 11.84% | | 1984 | 11.08 | 555.8 | 2.00% | 11.58% | | 1985 | 21.56 | 797.5 | 2.70% | 9.34% | | 1986 | 26.65 | 1266.7 | 2.10% | 7.60% | | 1987 | 24.40 | 1497.7 | 1.63% | 8.95% | | 1988 | 26.65 | 1541.3 | 1.73% | 9.00% | | 1989 | 27.00 | 1637.3 | 1.65% | 7.97% | | 1990 | 27.00 | 1637.3 | 1.63% | 8.24% |</p><p>十九年里，十九年我们资金成本低于长期国债收益率，十一年资金成本不到零，就是承保还赚钱，还给我们钱投资，这个结果真的很了不起，GEICO我们占48%，GEICO本身承保盈利，浮存金成本更低，所以伯克希尔整体保险资金成本真的很低。</p><p>这里要说明两点，第一，这个结果现在不对，要几十年后所有损失赔完才知道，所以我们现在说的，就是估计，肯定有误差，但是方向肯定对。第二，税收，股东拿到间接投资，还要交双倍税，所以这个税大概一个百分点，所以实际成本还要加一个百分点，就是这样，我们成本还是比绝大多数保险公司低很多，所以保险业务真的很值钱，GEICO本身效率高，定价准，所以浮存金成本真低，投保人给我们利息，我们太幸运了。</p><p>过去我犯过很多错，迈克·戈德堡来之前，我犯了很多错，保险就是容易犯错，错了几十年后还找你要钱，没有时效，所以我们现在就是这样，结果真的很好，保险业务价值远远超过账面价值。</p><h2 id="可交易证券" tabindex="-1">可交易证券 <a class="header-anchor" href="#可交易证券" aria-label="Permalink to &quot;可交易证券&quot;">​</a></h2><p>下面列出市值超过一亿普通股，小部分属于伯克希尔子公司：</p><table tabindex="0"><thead><tr><th>持股数</th><th>公司名称</th><th>成本</th><th>市值</th></tr></thead><tbody><tr><td>3,000,000</td><td>首都城市/ABC</td><td>517.5</td><td>1377.4</td></tr><tr><td>46,700,000</td><td>可口可乐</td><td>1023.9</td><td>2171.6</td></tr><tr><td>2,400,000</td><td>房地美优先股</td><td>71.7</td><td>117.0</td></tr><tr><td>6,850,000</td><td>GEICO</td><td>45.7</td><td>1110.6</td></tr><tr><td>1,727,765</td><td>华盛顿邮报</td><td>9.7</td><td>342.1</td></tr><tr><td>5,000,000</td><td>富国银行</td><td>289.4</td><td>289.4</td></tr></tbody></table><p>我们投资风格就是懒，今年我们六大重仓，一股没卖，买了富国银行，占到接近10%，美联储批准才能买这么多，我们六分之一是1989年买，剩下是1990年买的。</p><p>我们本来不喜欢银行业，银行业一般杠杆二十倍，一点点资产错误就能吃掉全部股权，过去很多大银行，经理都犯这个错，大家跟着领导走，大家都杠杆，都给垃圾贷款，结果就是大家一起完蛋，现在我们买富国银行，就是我们喜欢管理层，卡尔·赖卡特和保罗·黑曾，两个人，就像首都城市汤姆墨菲和丹伯克，两个人加起来比单独一个强，都知道控制成本，盈利好的时候也不敢乱扩张，下跌的时候也敢理性面对，我们就是喜欢这样管理层，所以我们在市场恐慌的时候，富国银行跌了一半，我们买了，花了两亿九千万，买了10%，相当于我们买整个银行五十亿，我们要是直接买整个银行，就是两倍价格，而且你买整个银行，你也找不到这么好管理层，所以我们很开心能打折买好管理层好银行。</p><p>当然，加州银行真的遇到地震，大地震房贷出事，加州房地产过度建设，会不会出大事，我们觉得概率低，就算出事，我们买的价格也不贵，就算亏，我们也能接受，反正一年亏了，我们也开心，我们伯克希尔就喜欢这样，好企业股价跌了，我们反而开心买，我们就是永远买，股价跌了对我们好，涨了对我们不好，我们就是这样，下跌我们买，因为我们知道，我们一直要买，所以下跌让我们买更便宜，当然，悲观带来低价，好公司降价你才能买，这不代表逆向投资就是对，你还是要思考，不是说大家悲观你就买，你得思考，但是很多时候，悲观的时候才有好价格，乐观的时候价格高对你不好。</p><p>巴菲特说，伯特兰·罗素说，&quot;大多数人宁愿死也不愿意思考，就是这样，很多人就是跟着群体走，&quot;所以我们就是独立思考，大家恐慌我们捡便宜，大家开心我们不一定买。</p><p>去年我们增持了很多RJR纳贝斯克债券，年底我们买了四亿四千万，现在价格涨了一亿五千万，我们买垃圾债，最近几年垃圾债就是骗局，八十年代出来，说高利息就能补偿违约，结果就是，很多垃圾债就是天生违约，因为发行的时候价格就不对，杠杆太高，哪怕经营好，利息也吃不消，所以现在就是满地都是坑，我们买了RJR，我们觉得还行，价格不错，发行人也不错，但是整体垃圾债现在还是坑，我们不碰新发行垃圾债，只有市场跌出来机会我们才看。</p><h2 id="总结几个要点" tabindex="-1">总结几个要点 <a class="header-anchor" href="#总结几个要点" aria-label="Permalink to &quot;总结几个要点&quot;">​</a></h2><p>我们透视盈利，现在吉莱特可转债转普通股，每年减少我们报告盈利大约三千五百万，透视盈利减少少一点，我们持股没问题。我们美国航空投资，我买了之后，行业马上出问题，就是我自己错，没看到航空业价格战这么激烈，所以就是我的错，现在CEO也改了，但是行业太差，所以投资不确定性更大，但是我们还是相信未来会好起来。</p><p>最后，我们吉尔特董事长科尔曼·莫格勒一月份去世了，他是真正绅士，正直，勇气，吉尔特就是一辈子专注品质，所以股东真的想念他。</p><p>我们公开招收购，条件就是： (1) 大额，税后盈利至少一千万， (2) 证明持续盈利能力，我们不要预测，不要扭转， (3) 高ROE，负债少最好没有负债， (4) 管理层在位，我们提供不了， (5) 业务简单，太复杂技术我们不懂， (6) 报价明确，我们不浪费时间。</p><p>我们不会敌意收购，我们保密，五分钟就能告诉你我们要不要，我们喜欢现金买，价格合适也换股，我们最喜欢卖家就是像布鲁姆金家族这样，原来老板想要现金，但是还想继续当大股东，继续经营，我们适合你们，欢迎符合条件的卖家联系我们。</p><p>今年年会四月二十九日周一，奥马哈奥菲亚剧院，欢迎你来，年会后周日二十八号，Borsheim正常关门，我们专门给股东开门，你一定要来，Borsheim Ikea Friedman家族都等着，来了你看看就知道，我们做生意方式真的不一样。</p><p>沃伦·E·巴菲特，董事长<br> 董事会主席</p>',50)])])}const h=e(n,[["render",a]]);export{x as __pageData,h as default};
